"use client";

import React, { useEffect, useState } from 'react';
import { Input } from './ui/input';
import { usePOSStore } from '@/store/posStore';

const BarcodeScanner = () => {
    const barcode = usePOSStore((state) => state.barcode);
    const setBarcode = usePOSStore(() => barcode);
    const resetBarcode = usePOSStore((state) => state.resetBarcode);
    const [scannedCode, setScannedCode] = useState<string>('');

    useEffect(() => {
        const handleBarcodeInput = (event: KeyboardEvent) => {
            const { key } = event;

            if (key === 'Enter') {
                console.log("Scanned barcode", barcode);
                resetBarcode;
                setScannedCode(barcode);
            } else if (key !== 'Backspace') {
                setBarcode;
            }
        };
        window.addEventListener('keydown', handleBarcodeInput);
        return () => {
            window.removeEventListener('keydown', handleBarcodeInput);
        };
    }, [barcode]);
    return (
        <div className="bg-white rounded-lg">
            <Input type="text" value={scannedCode} readOnly placeholder="Code" />
        </div>
    );
};

export default BarcodeScanner;
